import{_ as t,c,a1 as a,o as h}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Khắc phục Sự cố Mạng Cơ bản sử dụng MegaPing (Windows)","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/3-MegaPing.md","filePath":"vi/categories/ethical-hacking-labs/2-scanning-networks/3-MegaPing.md"}'),i={name:"vi/categories/ethical-hacking-labs/2-scanning-networks/3-MegaPing.md"};function e(r,n,g,o,s,u){return h(),c("div",null,n[0]||(n[0]=[a('<h1 id="khac-phuc-su-co-mang-co-ban-su-dung-megaping-windows" tabindex="-1">Khắc phục Sự cố Mạng Cơ bản sử dụng MegaPing (Windows) <a class="header-anchor" href="#khac-phuc-su-co-mang-co-ban-su-dung-megaping-windows" aria-label="Permalink to &quot;Khắc phục Sự cố Mạng Cơ bản sử dụng MegaPing (Windows)&quot;">​</a></h1><p>MegaPing là bộ công cụ toàn diện cung cấp đầy đủ các tiện ích thiết yếu cho quản trị viên IT và nhà cung cấp giải pháp.</p><p>Trang chính thức: <a href="http://www.magnetosoft.com/product/megaping/download" target="_blank" rel="noreferrer">http://www.magnetosoft.com/product/megaping/download</a></p><p>Với tiện ích MegaPing, bạn có thể phát hiện các máy chủ đang hoạt động, các cổng mở của hệ thống trong mạng. Bạn cũng có thể thực hiện các hoạt động khắc phục sự cố mạng khác nhau với sự trợ giúp của các tiện ích mạng được tích hợp, như DNS lookup name, DNS list hosts, Finger, host monitor, IP scanner, NetBios scanner, network time synchronizer, ping, port scanner, share scanner, traceroute và whois.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Phát hiện các máy chủ đang hoạt động và các cổng mở của hệ thống trong mạng.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Windows 7, 8 hoặc 10.</li><li>Windows Server 2012/2016 (máy mục tiêu).</li></ul><hr><p>Sau khi cài đặt, khởi động ứng dụng trên máy Windows 10 của bạn.</p><h2 id="quet-cac-may-chu-đang-hoat-đong" tabindex="-1">Quét các Máy chủ Đang hoạt động <a class="header-anchor" href="#quet-cac-may-chu-đang-hoat-đong" aria-label="Permalink to &quot;Quét các Máy chủ Đang hoạt động&quot;">​</a></h2><p>Phần mềm này rất dễ sử dụng. Để bắt đầu quét, nhấp vào <strong>IP Scanner</strong> trên bảng bên trái.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2e4f6b59a182462ca77ffd6888b14e0eeede313d/megaPing.png" alt="alt text" title="MegaPing"></p><ul><li>Chỉ định <strong>phạm vi IP</strong> của lab mạng của bạn, sau đó nhấp bắt đầu.</li><li>Lưu ý hộp kiểm ở bên phải, bạn có thể xem <strong>địa chỉ MAC</strong> từ các máy chủ bạn đã thu thập.</li></ul><p>MegaPing liệt kê tất cả các địa chỉ IP trong phạm vi mục tiêu đã chỉ định cùng với <strong>TTL</strong>, <strong>Trạng thái</strong> (chết hoặc sống) và thống kê của chúng.</p><h2 id="thuc-hien-traceroute-tren-muc-tieu" tabindex="-1">Thực hiện Traceroute trên Mục tiêu <a class="header-anchor" href="#thuc-hien-traceroute-tren-muc-tieu" aria-label="Permalink to &quot;Thực hiện Traceroute trên Mục tiêu&quot;">​</a></h2><ul><li>Nhấp chuột phải vào một địa chỉ IP, và nhấp <strong>Traceroute</strong>.</li></ul><p>Hành động này sẽ thực hiện Traceroute, hiển thị số bước nhảy (hop) mà máy chủ thực hiện để đến được mục tiêu.</p><h2 id="thuc-hien-quet-cong-tren-may-chu-muc-tieu" tabindex="-1">Thực hiện Quét Cổng trên Máy chủ Mục tiêu <a class="header-anchor" href="#thuc-hien-quet-cong-tren-may-chu-muc-tieu" aria-label="Permalink to &quot;Thực hiện Quét Cổng trên Máy chủ Mục tiêu&quot;">​</a></h2><ul><li>Tiếp theo chọn <strong>Port Scanner</strong> trên bảng bên trái.</li><li>Nhập địa chỉ IP của máy mục tiêu vào phần <strong>Destination Address List</strong>, và nhấp <strong>Add</strong>.</li></ul><p>Hành động này sẽ liệt kê tất cả các cổng liên quan đến mục tiêu, cùng với <strong>loại cổng, từ khóa, rủi ro và mô tả</strong>, như hiển thị trong ảnh chụp màn hình sau:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c7ebf540a2bb39c7a989b87716bc23fd1151dbb8/megaPing-PortScanner.png" alt="alt text" title="MegaPing Port Scanner"></p><p>Lưu ý: Bạn cũng có thể tạo báo cáo dưới dạng file HTML cho mỗi lần quét.</p><p><strong>Kết luận</strong>: Trình quét bảo mật MegaPing kiểm tra mạng của bạn để tìm các lỗ hổng tiềm ẩn có thể được sử dụng bởi kẻ tấn công.</p>',24)]))}const p=t(i,[["render",e]]);export{m as __pageData,p as default};
